Could you try the following C program on your 14-CURRENT host ?

-------------------
/* rlnkat.c */

#include <sys/stat.h>

#include <fcntl.h>
#include <unistd.h>
#include <stdio.h>
#include <strings.h>

#define BUFSIZE 1024

int
main(int argc, char** argv)
{
  int i,ret;
  char buffer[BUFSIZE];
  struct stat st;

  for(i = 1; i < argc; i++) {
    bzero( buffer, sizeof( buffer ));
    ret = fstatat( AT_FDCWD, argv[i], &st, AT_SYMLINK_NOFOLLOW );
    if( -1 == ret ) {
      perror("fstatat");
      continue;
    }
    if( S_ISLNK( st.st_mode )) {
      ret = readlinkat( AT_FDCWD, argv[i], buffer, sizeof( buffer ));
      if( -1 == ret ) {
        perror("readlinkat");
      } else {
        fprintf(stderr, "%d. %s symlink to %s\n", i, argv[i], buffer );
      }
    } else {
      fprintf( stderr, "%d. %s (is directory: %d)\n", i, argv[i], S_ISDIR( st.st_mode));
    }
  }
  return 0;
}
